<script lang="ts">import '../app.css';import {page} from '$app/state';let {data,children}= $props();function change(e:Event){const id=(e.currentTarget as HTMLSelectElement).value;const u=new URL(page.url);u.searchParams.set('dataset',id);location.href=u.pathname+u.search}</script>
<svelte:head><title>D-MON Presence</title><meta name="description" content="Local team activity dashboard"/></svelte:head>
<div class="shell"><header class="top"><div class="brand"><span>D-MON</span> Presence</div><nav class="nav"><a href="/?dataset={data.id}">Ranking</a><a href="/monthly?dataset={data.id}">Monthly</a><a href="/matches?dataset={data.id}">Matches</a><a href="/training?dataset={data.id}">Training</a><a href="/quality?dataset={data.id}">Data quality</a></nav>{#if data.all.length}<select aria-label="Team and season" onchange={change} value={data.id}>{#each data.all as d}<option value={d.id}>{d.displayName} · {d.season}</option>{/each}</select>{/if}</header>{@render children()}</div>
<style>:global(.shell){max-width:1900px}</style>
